import os
import joblib
from google.cloud import storage

def download_model_from_gcs(bucket_name, blob_name, destination_file_path):
    storage_client = storage.Client()
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(blob_name)
    blob.download_to_filename(destination_file_path)

def load_model(model_path):
    return joblib.load(model_path)

def main():
    model_path_env_var = 'MODEL_PATH'
    if model_path_env_var not in os.environ:
        raise ValueError(f"Environment variable {model_path_env_var} is not set")

    model_path = os.environ[model_path_env_var]
    
    # Check if the path is a GCS URL
    if model_path.startswith('gs://'):
        bucket_name, blob_name = model_path[5:].split('/', 1)
        destination_file_path = '/tmp/model.pkl'
        download_model_from_gcs(bucket_name, blob_name, destination_file_path)
        model_path = destination_file_path

    model = load_model(model_path)
    print("Model loaded successfully")

if __name__ == "__main__":
    main()